import base64, pathlib

FILES = {
  "src/app/commander/CommanderClient.tsx": "",
  "src/app/confirmation/ConfirmationClient.tsx": "",
  "src/app/mes-commandes/MesCommandesClient.tsx": "",
  "src/app/mon-espace/MonEspaceClient.tsx": "",
  "src/app/recharger/RechargerClient.tsx": "",
  "src/components/CartBar.tsx": "",
  "src/components/Navbar.tsx": "",
}

changed = 0
for path, data in FILES.items():
    p = pathlib.Path(path)
    p.parent.mkdir(parents=True, exist_ok=True)
    new = base64.b64decode(data)
    old = p.read_bytes() if p.exists() else b""
    if old != new:
        p.write_bytes(new)
        changed += 1
        print(f"  MODIFIE {path}")
    else:
        print(f"  identique {path}")

print(f"\n{changed} fichier(s) modifie(s).")
if changed > 0:
    print("Fais: git add -A && git commit -m \"fix: clean rebuild + nbsp\" && git push")
